/*! Spark — Anvilforge's reactive component runtime.
 *  Loaded via @sparkScripts; binds spark:* attributes and round-trips to
 *  /_spark/update. No external dependencies.
 */
(function () {
  'use strict';

  // ─── Boot data (from `window.__spark_boot` emitted by @sparkScripts) ─────
  var BOOT = (window && window.__spark_boot) || {
    csrf: '',
    endpoint: '/_spark/update',
    mounts: [],
  };

  function csrfHeaders() {
    return {
      'Content-Type': 'application/json',
      'X-CSRF-TOKEN': BOOT.csrf || '',
      Accept: 'application/json',
    };
  }

  // ─── Component registry ──────────────────────────────────────────────────
  // Each component is identified by its root element's `spark:id` attribute.
  // We don't keep state in JS; the snapshot lives on the DOM as `spark:snapshot`.
  function componentRoot(el) {
    while (el && el.nodeType === 1) {
      if (el.hasAttribute && el.hasAttribute('spark:id')) return el;
      el = el.parentNode;
    }
    return null;
  }

  function snapshotOf(root) {
    return root.getAttribute('spark:snapshot') || '';
  }

  function setSnapshot(root, wire) {
    root.setAttribute('spark:snapshot', wire);
  }

  // ─── morphdom-lite ───────────────────────────────────────────────────────
  // Minimal DOM morphing. Preserves focus on inputs and respects spark:ignore.
  function morph(fromNode, toNode) {
    if (fromNode.nodeType !== toNode.nodeType) {
      fromNode.parentNode && fromNode.parentNode.replaceChild(toNode, fromNode);
      return toNode;
    }
    if (fromNode.nodeType === 3) {
      if (fromNode.nodeValue !== toNode.nodeValue) fromNode.nodeValue = toNode.nodeValue;
      return fromNode;
    }
    if (fromNode.nodeType !== 1) return fromNode;
    if (fromNode.tagName !== toNode.tagName) {
      fromNode.parentNode && fromNode.parentNode.replaceChild(toNode, fromNode);
      return toNode;
    }
    if (fromNode.hasAttribute && fromNode.hasAttribute('spark:ignore')) return fromNode;

    // Attributes: diff sets.
    var fromAttrs = fromNode.attributes;
    for (var i = fromAttrs.length - 1; i >= 0; i--) {
      var name = fromAttrs[i].name;
      if (!toNode.hasAttribute(name)) fromNode.removeAttribute(name);
    }
    var toAttrs = toNode.attributes;
    for (var j = 0; j < toAttrs.length; j++) {
      var a = toAttrs[j];
      if (fromNode.getAttribute(a.name) !== a.value) {
        fromNode.setAttribute(a.name, a.value);
      }
    }

    // Form value preservation: inputs with spark:model keep user-typed value
    // unless server explicitly changed it.
    if (
      fromNode.tagName === 'INPUT' ||
      fromNode.tagName === 'TEXTAREA' ||
      fromNode.tagName === 'SELECT'
    ) {
      if (fromNode.hasAttribute('spark:model')) {
        var newVal = toNode.getAttribute('value');
        if (newVal !== null && fromNode.value !== newVal) {
          fromNode.value = newVal;
        }
      }
    }

    // Children: pairwise morph + tail adjust.
    var fc = fromNode.firstChild;
    var tc = toNode.firstChild;
    while (fc || tc) {
      if (!tc) {
        var nextFc = fc.nextSibling;
        fromNode.removeChild(fc);
        fc = nextFc;
        continue;
      }
      if (!fc) {
        var nextTc = tc.nextSibling;
        fromNode.appendChild(tc);
        tc = nextTc;
        continue;
      }
      var nextFromSibling = fc.nextSibling;
      var nextToSibling = tc.nextSibling;
      morph(fc, tc);
      fc = nextFromSibling;
      tc = nextToSibling;
    }
    return fromNode;
  }

  function parseHtml(html) {
    var wrapper = document.createElement('div');
    wrapper.innerHTML = html.trim();
    return wrapper.firstChild;
  }

  // ─── Request batching ────────────────────────────────────────────────────
  function sendUpdate(componentRoot, payload) {
    return fetch(BOOT.endpoint || '/_spark/update', {
      method: 'POST',
      headers: csrfHeaders(),
      body: JSON.stringify({
        _token: BOOT.csrf || '',
        components: [
          Object.assign(
            { snapshot: snapshotOf(componentRoot), updates: [], calls: [] },
            payload
          ),
        ],
      }),
    })
      .then(function (resp) {
        if (resp.status === 419) {
          // Snapshot expired — reload.
          window.location.reload();
          throw new Error('snapshot expired');
        }
        if (!resp.ok) {
          return resp.text().then(function (t) {
            throw new Error('spark: ' + resp.status + ' ' + t);
          });
        }
        return resp.json();
      })
      .then(function (body) {
        if (!body || !body.components || !body.components.length) return;
        var result = body.components[0];
        applyResult(componentRoot, result);
      });
  }

  function applyResult(currentRoot, result) {
    // Set the new snapshot first so the boot reflection sees it.
    setSnapshot(currentRoot, result.snapshot);

    // Apply islands (partial morph) if present; else morph the whole subtree.
    if (result.effects && result.effects.islands && result.effects.islands.length) {
      result.effects.islands.forEach(function (island) {
        var target = currentRoot.querySelector(
          '[spark\\:island="' + island.name + '"]'
        );
        if (!target) return;
        var fragment = parseHtml(island.html);
        if (fragment) morph(target, fragment);
      });
    } else if (result.html) {
      var newRoot = parseHtml(result.html);
      if (newRoot) morph(currentRoot, newRoot);
    }

    // Side effects.
    if (result.effects) {
      (result.effects.dispatched || []).forEach(function (d) {
        window.dispatchEvent(new CustomEvent(d.event, { detail: d.payload }));
      });
      (result.effects.emitted || []).forEach(function (e) {
        window.dispatchEvent(
          new CustomEvent('spark:emit:' + e.event, { detail: e.payload })
        );
      });
      if (result.effects.redirect) {
        window.location.href = result.effects.redirect;
      }
    }
  }

  // ─── Event binding ───────────────────────────────────────────────────────
  // We attach a small set of capturing handlers at document level. Each handler
  // walks up to the nearest spark:* attribute and dispatches accordingly.

  function parseAction(value) {
    // Accepts `methodName` or `methodName(arg1, arg2)`.
    var m = /^([A-Za-z_][A-Za-z0-9_]*)(\((.*)\))?$/.exec((value || '').trim());
    if (!m) return null;
    var method = m[1];
    var argsList = (m[3] || '').trim();
    var params = [];
    if (argsList.length) {
      // Naive split on top-level commas. Wrapped strings respected.
      params = splitCommaArgs(argsList).map(function (a) {
        return parseLiteral(a.trim());
      });
    }
    return { method: method, params: params };
  }

  function splitCommaArgs(s) {
    var out = [];
    var depth = 0;
    var inString = null;
    var start = 0;
    for (var i = 0; i < s.length; i++) {
      var c = s.charAt(i);
      if (inString) {
        if (c === inString && s.charAt(i - 1) !== '\\') inString = null;
        continue;
      }
      if (c === '"' || c === "'") { inString = c; continue; }
      if (c === '(' || c === '[' || c === '{') depth++;
      else if (c === ')' || c === ']' || c === '}') depth--;
      else if (c === ',' && depth === 0) {
        out.push(s.substring(start, i));
        start = i + 1;
      }
    }
    if (start < s.length) out.push(s.substring(start));
    return out;
  }

  function parseLiteral(s) {
    if (s === 'true') return true;
    if (s === 'false') return false;
    if (s === 'null') return null;
    if (/^-?\d+$/.test(s)) return parseInt(s, 10);
    if (/^-?\d+\.\d+$/.test(s)) return parseFloat(s);
    if ((s.startsWith('"') && s.endsWith('"')) || (s.startsWith("'") && s.endsWith("'"))) {
      return s.substring(1, s.length - 1);
    }
    return s; // fall through as raw string
  }

  function dispatchAction(root, parsed, opts) {
    if (!root || !parsed) return;
    var calls = [{ method: parsed.method, params: parsed.params, island: opts && opts.island }];
    return sendUpdate(root, { calls: calls });
  }

  function dispatchUpdate(root, name, value) {
    if (!root) return;
    var updates = [{ name: name, value: value }];
    return sendUpdate(root, { updates: updates });
  }

  // ─── spark:click ─────────────────────────────────────────────────────────
  document.addEventListener('click', function (event) {
    var el = event.target;
    while (el && el !== document) {
      if (el.hasAttribute && el.hasAttribute('spark:click')) {
        var action = parseAction(el.getAttribute('spark:click'));
        if (!action) return;
        var root = componentRoot(el);
        if (!root) return;
        toggleLoading(root, true);
        dispatchAction(root, action).finally(function () { toggleLoading(root, false); });
        return;
      }
      el = el.parentNode;
    }
  });

  // ─── spark:submit ────────────────────────────────────────────────────────
  document.addEventListener('submit', function (event) {
    var form = event.target;
    if (!form || !form.hasAttribute || !form.hasAttribute('spark:submit')) return;
    event.preventDefault();
    var action = parseAction(form.getAttribute('spark:submit'));
    if (!action) return;
    var root = componentRoot(form);
    if (!root) return;
    var data = new FormData(form);
    var updates = [];
    data.forEach(function (val, key) { updates.push({ name: key, value: val }); });
    var calls = [{ method: action.method, params: action.params }];
    toggleLoading(root, true);
    sendUpdate(root, { updates: updates, calls: calls }).finally(function () {
      toggleLoading(root, false);
    });
  });

  // ─── spark:keydown.<key> ─────────────────────────────────────────────────
  document.addEventListener('keydown', function (event) {
    var el = event.target;
    while (el && el !== document) {
      if (el.attributes) {
        for (var i = 0; i < el.attributes.length; i++) {
          var attr = el.attributes[i];
          var m = /^spark:keydown\.(.+)$/.exec(attr.name);
          if (m && m[1].toLowerCase() === event.key.toLowerCase()) {
            var action = parseAction(attr.value);
            if (!action) return;
            var root = componentRoot(el);
            if (!root) return;
            dispatchAction(root, action);
            return;
          }
        }
      }
      el = el.parentNode;
    }
  });

  // ─── spark:model[.modifiers] ─────────────────────────────────────────────
  var pendingModel = new WeakMap();
  function findModelAttr(el) {
    if (!el.attributes) return null;
    for (var i = 0; i < el.attributes.length; i++) {
      var a = el.attributes[i];
      if (a.name === 'spark:model' || a.name.indexOf('spark:model.') === 0) {
        return { attr: a.name, value: a.value };
      }
    }
    return null;
  }

  function handleModelChange(el, event) {
    var info = findModelAttr(el);
    if (!info) return;
    var modifiers = info.attr.split('.').slice(1);
    var live = modifiers.indexOf('live') !== -1;
    var lazy = modifiers.indexOf('lazy') !== -1;
    var debounceModifier = modifiers.find(function (m) { return /^debounce$/.test(m); });
    var hasDebounceMs = false;
    var debounceMs = 300;
    for (var i = 0; i < modifiers.length; i++) {
      var ms = /^(\d+)ms$/.exec(modifiers[i]);
      if (ms) { debounceMs = parseInt(ms[1], 10); hasDebounceMs = true; }
    }
    var name = info.value;
    var value = (el.type === 'checkbox') ? !!el.checked : el.value;
    var root = componentRoot(el);
    if (!root) return;
    if (lazy && event.type !== 'change' && event.type !== 'blur') return;
    if (!live && !lazy && event.type !== 'input' && event.type !== 'change') return;

    var dispatch = function () {
      dispatchUpdate(root, name, value);
      pendingModel.delete(el);
    };

    if (live || hasDebounceMs || debounceModifier) {
      var existing = pendingModel.get(el);
      if (existing) clearTimeout(existing);
      pendingModel.set(el, setTimeout(dispatch, debounceMs));
    } else {
      dispatch();
    }
  }

  document.addEventListener('input', function (event) {
    handleModelChange(event.target, event);
  });
  document.addEventListener('change', function (event) {
    handleModelChange(event.target, event);
  });
  document.addEventListener('blur', function (event) {
    handleModelChange(event.target, event);
  }, true);

  // ─── spark:loading toggles ──────────────────────────────────────────────
  function toggleLoading(root, isLoading) {
    if (!root) return;
    var elems = root.querySelectorAll('[spark\\:loading], [spark\\:loading\\.remove], [spark\\:loading\\.attr]');
    elems.forEach(function (el) {
      // Delay support: spark:loading.delay.200ms
      var hasDelay = false;
      var delayMs = 200;
      for (var i = 0; i < el.attributes.length; i++) {
        var name = el.attributes[i].name;
        if (name.indexOf('spark:loading.delay.') === 0) {
          hasDelay = true;
          var m = /(\d+)ms/.exec(name);
          if (m) delayMs = parseInt(m[1], 10);
        }
      }
      var remove = el.hasAttribute('spark:loading.remove');
      var attrToggle = el.getAttribute('spark:loading.attr');

      var apply = function () {
        if (attrToggle) {
          if (isLoading) el.setAttribute(attrToggle, '');
          else el.removeAttribute(attrToggle);
          return;
        }
        if (remove) {
          el.style.display = isLoading ? 'none' : '';
          return;
        }
        el.style.display = isLoading ? '' : 'none';
      };

      if (hasDelay && isLoading) {
        el.__sparkLoadingTimer = setTimeout(apply, delayMs);
      } else {
        if (el.__sparkLoadingTimer) {
          clearTimeout(el.__sparkLoadingTimer);
          el.__sparkLoadingTimer = null;
        }
        apply();
      }
    });
  }

  // Default hide for any spark:loading element on first paint.
  function initLoadingDefaults() {
    document.querySelectorAll('[spark\\:loading]').forEach(function (el) {
      if (!el.hasAttribute('spark:loading.remove') && !el.hasAttribute('spark:loading.attr')) {
        el.style.display = 'none';
      }
    });
  }

  // ─── spark:poll[.<ms>] ───────────────────────────────────────────────────
  function initPolling() {
    document.querySelectorAll('[spark\\:poll]').forEach(function (el) {
      var attr = null;
      for (var i = 0; i < el.attributes.length; i++) {
        if (el.attributes[i].name.indexOf('spark:poll') === 0) {
          attr = el.attributes[i];
          break;
        }
      }
      if (!attr) return;
      var ms = 2000;
      var m = /spark:poll\.(\d+)ms/.exec(attr.name);
      if (m) ms = parseInt(m[1], 10);
      var action = parseAction(attr.value || 'refresh');
      if (!action) return;
      var root = componentRoot(el);
      if (!root) return;
      setInterval(function () {
        if (document.hidden) return;
        dispatchAction(root, action);
      }, ms);
    });
  }

  // ─── Echo (WebSocket) subscription for #[spark::on] listeners ────────────
  function initEchoSubscriptions() {
    if (!BOOT.mounts || !BOOT.mounts.length) return;
    // We try to use Laravel Echo if loaded; otherwise we fall back to raw
    // WebSocket against Bellows' Pusher-protocol endpoint.
    var hasEcho = window.Echo && typeof window.Echo.channel === 'function';
    BOOT.mounts.forEach(function (mount) {
      (mount.listeners || []).forEach(function (eventName) {
        if (hasEcho) {
          var channel = inferChannel(eventName);
          window.Echo.channel(channel).listen('.' + eventName, function (payload) {
            triggerBroadcast(mount.id, eventName, payload);
          });
        }
      });
    });
  }
  function inferChannel(eventName) {
    var dot = eventName.indexOf('.');
    return dot > 0 ? eventName.substring(0, dot) : eventName;
  }
  function triggerBroadcast(componentId, eventName, payload) {
    var root = document.querySelector('[spark\\:id="' + componentId + '"]');
    if (!root) return;
    var calls = [{ method: '__on_broadcast', params: [eventName, payload || null] }];
    sendUpdate(root, { calls: calls });
  }

  // ─── Public API ──────────────────────────────────────────────────────────
  var Spark = {
    start: function () {
      initLoadingDefaults();
      initPolling();
      initEchoSubscriptions();
    },
    boot: BOOT,
    dispatch: function (event, payload) {
      window.dispatchEvent(new CustomEvent(event, { detail: payload }));
    },
    on: function (event, fn) {
      window.addEventListener('spark:emit:' + event, function (e) {
        fn(e.detail);
      });
    },
    request: function (componentId, payload) {
      var root = document.querySelector('[spark\\:id="' + componentId + '"]');
      if (root) sendUpdate(root, payload);
    },
  };
  window.Spark = Spark;

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', function () { Spark.start(); });
  } else {
    Spark.start();
  }
})();
